SELECT SUM(cnt) AS total_rentals
FROM bike_rental_data
WHERE date(start_time) = '2023-01-01';

SELECT rental_date
FROM rentals_by_station
WHERE cnt = (SELECT MAX(cnt) FROM rentals_by_station);

SELECT station_id, AVG(duration_minutes) AS average_duration, COUNT(*) AS total_rentals
FROM bike_rental_data
GROUP BY station_id;

SELECT SUM(cnt) AS total_rentals
FROM rentals_by_station
WHERE station_id = 1 AND rental_date = '2023-05-01';

SELECT station_id, COUNT(*) AS total_rentals
   FROM bike_rental_data
   GROUP BY station_id;
